What does this program print?

```cpp
#include <iostream>
struct Temp {
    double v{};
    Temp operator-() const { return Temp{ -v }; }
};
int main() {
    Temp t{ 5.0 };
    Temp u = -t;
    std::cout << t.v << ' ' << u.v << '\n';
}
```

